import React from 'react';

const WorkflowStep = ({ name, status }) => {
  const getStatusStyles = () => {
    switch (status) {
      case 'completed':
        return 'bg-green-500 text-white';
      case 'current':
        return 'bg-blue-500 text-white';
      default:
        return 'bg-gray-200 text-gray-600';
    }
  };

  return (
    <div className="flex items-center my-1">
      <div className={`w-6 h-6 rounded-full flex items-center justify-center mr-3 text-sm ${getStatusStyles()}`}>
        {status === 'completed' ? '✓' : '●'}
      </div>
      <span>{name}</span>
    </div>
  );
};

const WorkflowTracker = () => {
  // This will be driven by session state later
  const steps = [
    { name: 'Define Goal', status: 'completed' },
    { name: 'Prepare Data', status: 'current' },
    { name: 'Select Method', status: 'upcoming' },
    { name: 'Configure Job', status: 'upcoming' },
    { name: 'Execute', status: 'upcoming' },
    { name: 'Review Results', status: 'upcoming' },
  ];

  return (
    <Card>
        <h3 className="font-bold mb-3">Workflow Progress</h3>
        <div>
        {steps.map((step, index) => (
            <WorkflowStep key={index} name={step.name} status={step.status} />
        ))}
        </div>
    </Card>
  );
};

export default WorkflowTracker;
